// C2: el agente devuelve ids; los datos salen de Postgres.
// Todo el bloque va en try/catch: si algo acá tira, el usuario tiene que recibir
// una burbuja igual (mismo blindaje que tenía Responder a Render).
const cfg = $('Config').first().json;

function fallback(motivo) {
  const msgs = [{ type: 'text', content: 'Uy, se me trabó el sistema un segundo. Me repetís lo último?' }];
  return [{ json: {
    respuesta: { session_id: cfg.session_id, messages: msgs, images: [], product_cards: [], error: null },
    historial: { messages: msgs, images: [], product_cards: [] },
    debug_motivo: motivo,
  } }];
}

try {
  const crudo = $('Franco (AI Agent)').first().json.output;
  const output = (crudo && typeof crudo === 'object' && !Array.isArray(crudo)) ? crudo : {};

  // Filas hidratadas. alwaysOutputData deja un item vacío cuando no hubo ids.
  const filas = $('Hidratar autos').all()
    .map(i => i.json)
    .filter(r => r && r.id != null);

  // El orden lo manda Franco (es el orden en que los nombra en el texto).
  // = ANY no preserva orden, así que reordenamos por auto_ids.
  const ids = Array.isArray(output.auto_ids)
    ? output.auto_ids.map(n => parseInt(n, 10)).filter(n => Number.isInteger(n))
    : [];
  const porId = new Map(filas.map(r => [Number(r.id), r]));

  // Autos cuyas FOTOS ya se mandaron en los últimos 8 mensajes de esta sesión. Viene como
  // "2,5,14" desde "Autos ya mostrados"; si no hay nada, viene ''. Sólo mira `images`
  // previas: haber aparecido como card NO cuenta, porque ver la ficha con fotos después de
  // la miniatura es un flujo válido.
  let yaMostrados = new Set();
  try {
    const crudoIds = String($('Autos ya mostrados').first().json.ids_recientes || '');
    yaMostrados = new Set(crudoIds.split(',').map(s => parseInt(s, 10)).filter(n => Number.isInteger(n)));
  } catch (e) {
    // Si el nodo no devolvió nada, no filtramos: preferimos repetir una foto antes que
    // dejar al cliente sin ver el auto.
  }
  // Autos cuyas CARDS (product_cards) ya se mandaron en los últimos 8 mensajes. Pedido de
  // Agustina: no repetir el mismo mazo cuando el cliente sigue hablando de esos autos.
  let cardsMostradas = new Set();
  try {
    const crudoCards = String($('Autos ya mostrados').first().json.cards_recientes || '');
    cardsMostradas = new Set(crudoCards.split(',').map(s => parseInt(s, 10)).filter(n => Number.isInteger(n)));
  } catch (e) {}
  const autos = [...new Set(ids)].map(id => porId.get(id)).filter(Boolean);

  let messages = Array.isArray(output.messages)
    ? output.messages.filter(m => m && typeof m.content === 'string' && m.content.trim())
    : [];
  if (messages.length === 0) {
    messages = [{ type: 'text', content: 'Uy, se me trabó el sistema un segundo. Me repetís lo último?' }];
  }
  // Las fotos cuelgan de la última burbuja de contenido, antes de que el guard
  // de cierre agregue la pregunta.
  // TB-3: encabezado del abanico de permuta por CÓDIGO (mata el eco de los datos del usado). Solo cuando
  // Listar stock corrió como capacidad/permuta (mira sus flags). Compone SOLO con lo que hay: nunca inventa
  // un usado, un anticipo ni un efectivo que el cliente no dio.
  try {
    if (autos.length >= 3) {
      // el tool Listar stock envuelve las filas en { response: [...] }; los flags están en la fila.
      let ls = {};
      try {
        const _raw = $('Listar stock').first().json;
        ls = (_raw && Array.isArray(_raw.response)) ? (_raw.response[0] || {}) : (_raw || {});
      } catch (e) {}
      let permuta = Number(ls.eco_permuta) === 1;
      let financia = Number(ls.eco_financia) === 1;
      let presu = Number(ls.eco_presu) === 1;
      // fallback si no se pudo leer del tool: usar el estado del CRM (nodo main-chain, siempre accesible).
      if (ls.eco_permuta == null) {
        try {
          const le = $('Leer lead (estado)').first().json;
          permuta = String(le.lead_entrega || '') === 'Sí' || (le.lead_usado && le.lead_usado !== 'No mencionado');
          financia = String(le.lead_financia || '') === 'Si';
          presu = le.lead_presupuesto && le.lead_presupuesto !== 'No mencionado';
        } catch (e) {}
      }
      if (permuta || financia) {
        const partes = [];
        if (permuta) partes.push('tu usado como parte de pago');
        if (presu) partes.push(financia ? 'tu anticipo' : 'tu efectivo');
        if (financia) partes.push('la posibilidad de financiar');
        if (partes.length) {
          const unir = partes.length === 1 ? partes[0] : partes.slice(0, -1).join(', ') + ' y ' + partes[partes.length - 1];
          const encabezado = 'Con ' + unir + ', estas opciones te pueden servir:';
          // buscar la burbuja que tiene la lista de autos (viñetas)
          let ib = -1, li = -1;
          for (let k = 0; k < messages.length; k++) {
            const c = String(messages[k].content || '');
            const j = c.search(/(^|\n)\s*[-•]/);
            if (j >= 0) { ib = k; li = j; break; }
          }
          if (ib >= 0) {
            const c = String(messages[ib].content || '');
            if (li > 0) {
              // encabezado y lista en la misma burbuja: reemplazo el texto antes de la lista
              messages[ib] = Object.assign({}, messages[ib], { content: encabezado + c.slice(li) });
            } else if (ib > 0) {
              // la lista arranca sola en su burbuja: la burbuja anterior es el encabezado (donde vive el eco)
              messages[ib - 1] = Object.assign({}, messages[ib - 1], { content: encabezado });
            }
          }
        }
      }
    }
  } catch (e) {}
  const anchor = messages.length - 1;

  // fotos viene de jsonb; n8n suele darlo como array, pero si llega como string
  // lo parseamos en vez de romper.
  function fotosDe(fila) {
    let f = fila.fotos;
    if (typeof f === 'string') { try { f = JSON.parse(f); } catch (e) { f = null; } }
    const arr = Array.isArray(f) ? f : [];
    const limpias = arr.filter(u => typeof u === 'string' && u);
    return limpias.length ? limpias : (fila.foto_principal ? [fila.foto_principal] : []);
  }

  let images = [];
  let product_cards = [];
  if (autos.length >= 3) {
    // Dedup del mazo: si TODOS los autos de este turno ya se mandaron como card hace poco,
    // no se repite (el cliente sigue hablando de esos y ya los tiene en pantalla). Si hay al
    // menos uno nuevo, va la lista completa: filtrar auto por auto dejaría huecos en el catálogo.
    const hayNuevo = autos.some(a => !cardsMostradas.has(Number(a.id)));
    if (hayNuevo) {
      product_cards = autos.map(a => ({
        id: a.id, titulo: a.titulo, precio: a.precio, foto_principal: a.foto_principal,
      }));
    }
  } else if (autos.length >= 1) {
    // Acá sí: si las fotos de este auto ya se mandaron hace poco, no se reenvían.
    const sinRepetir = autos.filter(a => !yaMostrados.has(Number(a.id)));
    images = sinRepetir.flatMap(fotosDe).map(url => ({ url, after_message_index: anchor }));
  }

  // Guard de cierre comercial: la respuesta nunca termina sin pregunta.
  let msgs = messages;
  const ultima = msgs[msgs.length - 1];
  const texto = (ultima && ultima.content) ? String(ultima.content).trim() : '';
  // El guard existe para que una LISTA DE AUTOS no quede sin pregunta de próximo paso.
  // Solo corre si este turno mostró autos: en turnos sin autos (despedida, derivación ya
  // cerrada, FAQ) pegar la pregunta genérica genera loops — le ofrecía un asesor a alguien
  // que ya lo había aceptado y dado su nombre. Medido sobre 39 turnos: de 4 disparos, los 2
  // con autos eran correctos y los 2 sin autos eran el bug.
  // Alcanza con que la última burbuja CONTENGA una pregunta: Franco a veces cierra con una
  // frase de cortesía después del "?", y con endsWith() el guard le pegaba otra encima.
  // Verificado por replay sobre 15 disparos guardados: 12 siguen disparando, y los 3 que
  // no, ya tenían pregunta propia. NO usar "alguna burbuja": el saludo tiene "?" y
  // desactivaría el guard casi siempre (se probó en v27 y se revirtió).
  if (autos.length >= 1 && !texto.includes('?')) {
    // Si el lead ya pidió que lo contacte un asesor, ofrecérselo otra vez es el bug de las
    // capturas 3-5. Se lee el estado que ya trae "Leer lead (estado)" en esta ejecución.
    // try/catch a propósito: este nodo arma la respuesta al usuario y no puede romperse
    // por el guard; ante cualquier duda, el texto de siempre.
    let yaDerivado = false;
    try { yaDerivado = $('Leer lead (estado)').first().json.lead_estado === 'Requiere asesor'; } catch (e) {}
    const cierre = product_cards.length >= 3
      ? 'Buscás algo puntual o querés que te ayude a encontrar el ideal según lo que necesitás?'
      : yaDerivado
        ? 'Cuál te llama la atención?'
        : 'Querés que un asesor te prepare una cotización, o preferís que te muestre algo parecido?';
    msgs = [...msgs, { type: 'text', content: cierre }];
  }
  msgs = msgs.map(m => Object.assign({}, m, {
    content: String(m.content || '').replace(/[¿¡]/g, ''),
  }));

  const esPrimero = $('Contar mensajes previos').first().json.msgs_previos === 0;
  const saludo = { type: 'text', content: 'Hola! Soy ' + cfg.asistente_nombre + ', asistente de ' + cfg.empresa_nombre + '. Cómo estás?' };
  const finalMsgs = esPrimero ? [saludo, ...msgs] : msgs;
  const finalImgs = esPrimero
    ? images.map(i => Object.assign({}, i, { after_message_index: (i.after_message_index || 0) + 1 }))
    : images;

  return [{ json: {
    respuesta: { session_id: cfg.session_id, messages: finalMsgs, images: finalImgs, product_cards, error: null },
    // M2: el historial guarda EXACTAMENTE lo que vio el cliente — saludo, pregunta de
    // cierre del guard y strip de ¿/¡ incluidos. Antes guardaba `messages`/`images` crudos,
    // así que la pestaña "Historial" (la pantalla que se le muestra al dueño en la demo)
    // mostraba una conversación sin saludo, sin cierre y con los ¿ que el cliente no vio.
    // No afecta al saludo: eso lo decide "Contar mensajes previos" sobre n8n_chat_histories,
    // que es otra tabla. Tampoco al CRM, que lee n8n_chat_histories.
    historial: { messages: finalMsgs, images: finalImgs, product_cards },
  } }];
} catch (e) {
  return fallback(String(e && e.message ? e.message : e));
}

